def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 10:
            temp_sum = 0
            for a in range(10, 5, -1):
                for b in range(1, a + 5):
                    term = ((ratio - a) ** 6) / (a * b * 1.1 + 2)
                    temp_sum += term * np.sin(ratio * b / (a + 2))
                    if b % 2 == 0:
                        temp_sum -= np.cos(ratio * a * b) / (b + a)
                    else:
                        temp_sum += np.tanh(ratio / (a + b))
            priority += np.power(np.exp(ratio - 10) * np.sin(ratio * 1.3), 2) + temp_sum
        elif 6 < ratio <= 10:
            s = 0
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    val = ((ratio - p) ** 4) * np.cos(ratio * q) / (q + 1.2)
                    s += np.tanh(val) * 1.3
            priority += s + np.log(ratio) * 15 - np.tanh(ratio - 6) * 3
        elif 3 <= ratio <= 6:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 3) ** r) / (r * 1.5) * np.sin(r * ratio)
            priority = (s * np.sin(5 * ratio)) - np.log(ratio) * 8 + np.tanh(3 * (6 - ratio)) * 2
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
                priority += penalty
        elif 1.2 <= ratio < 3:
            s = 0
            for n in range(1, 12):
                s += ((3 - ratio) ** n) / (n ** 2 + 1)
            penalty = 0
            if bin_cap < item * 1.05:
                penalty = np.cos(25 * ratio) * 3
            else:
                penalty = np.exp(-ratio) * 4
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i) * ((ratio - 1.2) ** m) / (m * 1.1)
        elif 0.5 <= ratio < 1.2:
            s = 0
            for x in range(1, 20):
                s += ((1.2 - ratio) ** x) / (x * 3)
            if (i + int(item * 2)) % 5 == 0:
                s *= np.log1p(bin_cap + 5) * 1.7
            else:
                s /= (np.sqrt(bin_cap + 2) + 1.5)
            penalty = 0
            if bin_cap < item * 0.8:
                penalty = np.sqrt(item / (bin_cap + 0.2)) * 6
            else:
                penalty = np.cos(15 * ratio) * 3.8
            priority = s + penalty + np.exp(-0.8 / (ratio + 0.08))
            for j in range(1, 9):
                priority += ((1.2 - ratio) ** j) * np.sin(j * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for y in range(1, 18):
                s += ((0.5 - ratio) ** y) / (y * 5) * np.cos(y * ratio * 3)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.8) % 5 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for z in range(1, 10):
                priority += ((0.5 - ratio) ** z) / (z * 7) * np.cos(item * z * 1.3)
        else:
            s = 0
            for w in range(1, 15):
                s += ((0.2 - ratio) ** w) / (w * 6) * np.sin(w * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 7 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for v in range(1, 12):
                priority += ((0.2 - ratio) ** v) / (v * 9) * np.cos(item * v * 0.85)
        if bin_cap < item * 0.5:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx)) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx)) * 0.35
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.65
        priorities[i] = priority
    return priorities
